function normalizeAssignmentStatus(status) {
  const raw = String(status || "").trim().toLowerCase();
  if (raw === "shared" || raw === "share" || raw === "shared_with_coach") return "shared";
  if (raw === "review" || raw === "in_progress" || raw === "in-progress" || raw === "progress") return "in_progress";
  if (raw === "complete" || raw === "completed") return "completed";
  if (raw === "overdue") return "overdue";
  return "not_started";
}

function normalizeAssignmentChecklist(raw = {}) {
  if (!raw || typeof raw !== "object") return {};
  return Object.entries(raw).reduce((acc, [key, value]) => {
    const safeKey = String(key || "").trim();
    if (!safeKey) return acc;
    acc[safeKey] = Boolean(value);
    return acc;
  }, {});
}

function normalizeAssignmentDiscussionEntry(raw = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const id = String(source.id || source.commentId || "").trim();
  const text = String(source.text || source.message || "").trim();
  const authorUid = normalizeUid(source.authorUid || source.userUid || source.senderUid || source.uid || "");
  const authorName = String(source.authorName || source.userName || source.senderName || source.name || "").trim();
  const authorRole = normalizeAuthRole(source.authorRole || source.role || "athlete");
  const stepId = String(source.stepId || "").trim();
  const stepLabel = String(source.stepLabel || source.exerciseLabel || "").trim();
  const createdAtIso = String(source.createdAtIso || source.createdAt || source.timestamp || "").trim();
  if (!id || !text || !authorUid) return null;
  return {
    id,
    text,
    authorUid,
    authorName: authorName || "User",
    authorRole: authorRole || "athlete",
    stepId,
    stepLabel,
    createdAtIso
  };
}

function normalizeAssignmentDiscussion(raw = []) {
  if (!Array.isArray(raw)) return [];
  const seen = new Set();
  const rows = [];
  raw.forEach((entry) => {
    const normalized = normalizeAssignmentDiscussionEntry(entry);
    if (!normalized || seen.has(normalized.id)) return;
    seen.add(normalized.id);
    rows.push(normalized);
  });
  rows.sort((left, right) => parseIsoTimestamp(left.createdAtIso) - parseIsoTimestamp(right.createdAtIso));
  return rows;
}

function normalizeAssignmentCompletionResult(raw = {}, assignment = null) {
  const source = raw && typeof raw === "object" ? raw : {};
  const type = String(source.type || source.resultType || "").trim().toLowerCase();
  const label = String(source.label || source.title || "").trim()
    || String(assignment?.mentalGameTitle || assignment?.title || "").trim();
  const summary = String(source.summary || source.resultSummary || "").trim();
  const scoreValue = Number(source.score);
  const reactionValue = Number(source.reactionMs);
  const accuracyValue = Number(source.accuracy);
  return {
    type: type || "task",
    label,
    summary,
    score: Number.isFinite(scoreValue) ? Math.round(scoreValue) : null,
    reactionMs: Number.isFinite(reactionValue) ? Math.max(0, Math.round(reactionValue)) : null,
    accuracy: Number.isFinite(accuracyValue) ? Math.max(0, Math.min(100, Math.round(accuracyValue))) : null
  };
}

function formatAssignmentDiscussionTime(value = "") {
  const ts = parseIsoTimestamp(value);
  if (!ts) return "";
  const locale = currentLang === "es" ? "es-ES" : "en-US";
  return new Date(ts).toLocaleString(locale, {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    timeZone: APP_TIMEZONE
  });
}

function normalizeCoachAssignmentRecord(id, data = {}) {
  const dueDateKey = isDateKey(data.dueDateKey) ? data.dueDateKey : "";
  const startDateKey = isDateKey(data.startDateKey)
    ? data.startDateKey
    : (isDateKey(data.weekStartKey) ? data.weekStartKey : dueDateKey);
  const endDateKey = isDateKey(data.endDateKey)
    ? data.endDateKey
    : (isDateKey(data.weekEndKey) ? data.weekEndKey : dueDateKey);
  const assigneeType = String(data.assigneeType || "athlete").trim().toLowerCase();
  const normalizedStatus = normalizeAssignmentStatus(data.status);
  const effectiveStatus = assigneeType === "coach" ? "shared" : normalizedStatus;
  const derivedStatus = dueDateKey && dueDateKey < getCurrentAppDateKey() && effectiveStatus !== "completed" && effectiveStatus !== "shared"
    ? "overdue"
    : effectiveStatus;
  const discussion = normalizeAssignmentDiscussion(data.discussion || []);
  const latestDiscussion = discussion.length ? discussion[discussion.length - 1] : null;
  return {
    id,
    title: String(data.title || "").trim(),
    assigneeType,
    assigneeName: String(data.assigneeName || "").trim(),
    assigneeNames: uniqueNames(data.assigneeNames || []),
    assigneeId: String(data.assigneeId || "").trim(),
    athleteIds: uniqueNames((data.athleteIds || []).map((value) => String(value || "").trim())).map((value) => String(value || "").trim()),
    athleteUids: uniqueNames((data.athleteUids || []).map((value) => String(value || "").trim())).map((value) => String(value || "").trim()),
    type: String(data.type || "Training Plan").trim(),
    startDateKey,
    endDateKey,
    dueDateKey,
    dueLabel: String(data.dueLabel || "").trim(),
    status: derivedStatus,
    note: String(data.note || "").trim(),
    source: String(data.source || "").trim(),
    planId: String(data.planId || "").trim(),
    planType: normalizePlanType(data.planType || "day"),
    scheduleMode: String(data.scheduleMode || "").trim().toLowerCase(),
    weekCount: Number.isFinite(Number(data.weekCount)) ? Number(data.weekCount) : 0,
    weekStartKey: isDateKey(data.weekStartKey) ? data.weekStartKey : startDateKey,
    weekEndKey: isDateKey(data.weekEndKey) ? data.weekEndKey : endDateKey,
    athleteChecklist: normalizeAssignmentChecklist(data.athleteChecklist),
    mediaId: String(data.mediaId || "").trim(),
    mediaTitle: String(data.mediaTitle || "").trim(),
    mediaAssetPath: String(data.mediaAssetPath || "").trim(),
    mediaAssetStoragePath: String(data.mediaAssetStoragePath || "").trim(),
    mediaThumbnailPath: String(data.mediaThumbnailPath || "").trim(),
    mediaThumbnailStoragePath: String(data.mediaThumbnailStoragePath || "").trim(),
    mediaType: String(data.mediaType || "").trim(),
    trainingTrack: String(data.trainingTrack || "").trim().toLowerCase(),
    liftingProtocolId: String(data.liftingProtocolId || "").trim(),
    liftingProtocolName: String(data.liftingProtocolName || "").trim(),
    liftingDayName: String(data.liftingDayName || "").trim(),
    mentalGameKey: String(data.mentalGameKey || "").trim().toLowerCase(),
    mentalGameTitle: String(data.mentalGameTitle || "").trim(),
    mentalGameDuration: Number.isFinite(Number(data.mentalGameDuration)) ? Number(data.mentalGameDuration) : 0,
    discussion,
    discussionCount: discussion.length,
    latestDiscussion,
    notifiedAt: normalizeFirestoreDateValue(data.notifiedAt),
    notificationStatus: String(data.notificationStatus || "").trim(),
    completionNotifiedAt: normalizeFirestoreDateValue(data.completionNotifiedAt),
    completionResultType: String(data.completionResultType || "").trim().toLowerCase(),
    completionResultLabel: String(data.completionResultLabel || "").trim(),
    completionResultSummary: String(data.completionResultSummary || "").trim(),
    completionResultScore: Number.isFinite(Number(data.completionResultScore)) ? Number(data.completionResultScore) : null,
    completionResultReactionMs: Number.isFinite(Number(data.completionResultReactionMs)) ? Number(data.completionResultReactionMs) : null,
    completionResultAccuracy: Number.isFinite(Number(data.completionResultAccuracy)) ? Number(data.completionResultAccuracy) : null,
    completionResultAt: normalizeFirestoreDateValue(data.completionResultAt),
    createdAt: normalizeFirestoreDateValue(data.createdAt),
    updatedAt: normalizeFirestoreDateValue(data.updatedAt)
  };
}

function defaultPlanTitle(type = planRangeType) {
  const map = {
    day: { en: "Daily Training Plan", es: "Plan diario de entrenamiento" },
    week: { en: "Weekly Training Plan", es: "Plan semanal de entrenamiento" },
    month: { en: "Monthly Training Plan", es: "Plan mensual de entrenamiento" },
    season: { en: "Season Training Plan", es: "Plan de temporada" }
  };
  return pickCopy(map[normalizePlanType(type)] || map.day);
}

function slugifyKey(value) {
  return stripUserDisplayNumber(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "") || `item-${Date.now()}`;
}

