function translateOptionValue(selectId, value) {
  if (!value) return value;
  const table = SELECT_COPY[selectId];
  if (!table) return value;
  const map = table[currentLang] || table.en;
  return map?.[value] || value;
}

function translateValue(value) {
  if (currentLang !== "es") return value;
  return VALUE_TRANSLATIONS_ES[value] || value;
}

function translateTechnique(name) {
  const copy = TECHNIQUE_LABELS[name];
  if (!copy) return name;
  return pickCopy(copy);
}

function translateTechniqueList(list) {
  return (list || []).map((item) => translateTechnique(item));
}

function getWeekPlanData() {
  return currentLang === "es" ? WEEK_PLAN_ES : WEEK_PLAN;
}

function getDatePartsInAppTime(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: APP_TIMEZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(date);
  const map = {};
  parts.forEach(({ type, value }) => {
    if (type !== "literal") map[type] = value;
  });
  return {
    year: Number.parseInt(map.year, 10),
    month: Number.parseInt(map.month, 10),
    day: Number.parseInt(map.day, 10)
  };
}

function getCurrentAppDate(date = new Date()) {
  const { year, month, day } = getDatePartsInAppTime(date);
  return new Date(year, month - 1, day);
}

function getCurrentAppDateKey(date = new Date()) {
  const { year, month, day } = getDatePartsInAppTime(date);
  return `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

function getCurrentAppDayIndex(date = new Date()) {
  return getCurrentAppDate(date).getDay();
}

function toDateKey(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function isDateKey(key) {
  return /^\d{4}-\d{2}-\d{2}$/.test(key);
}

function startOfWeek(date) {
  const d = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  d.setDate(d.getDate() - d.getDay());
  return d;
}

function addDays(date, days) {
  const d = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  d.setDate(d.getDate() + days);
  return d;
}

function stripUserDisplayNumber(value) {
  return String(value || "")
    .trim()
    .replace(/\s+#\d{4}\b/g, "")
    .trim();
}

function normalizeName(value) {
  return stripUserDisplayNumber(value || "").trim().toLowerCase();
}

function hashUserDisplaySeed(value = "") {
  const seed = String(value || "").trim().toLowerCase();
  let hash = 0;
  for (let index = 0; index < seed.length; index += 1) {
    hash = ((hash << 5) - hash) + seed.charCodeAt(index);
    hash |= 0;
  }
  return Math.abs(hash);
}

function getUserDisplayNumber(entity = {}) {
  const seed = [
    entity.uid,
    entity.user_id,
    entity.athleteUid,
    entity.linkedAthleteUid,
    entity.email,
    entity.athleteEmail,
    entity.id,
    entity.linkedAthleteId,
    stripUserDisplayNumber(entity.name || ""),
    stripUserDisplayNumber(entity.athleteName || ""),
    stripUserDisplayNumber(entity.linkedCoachName || "")
  ].find((candidate) => String(candidate || "").trim());
  return String(hashUserDisplaySeed(seed || "wpl-user") % 10000).padStart(4, "0");
}

function getDisplayNameWithNumber(name, entity = {}) {
  const rawName = stripUserDisplayNumber(name || entity.name || entity.email || entity.athleteName || "");
  if (!rawName) return "";
  return rawName;
}

function escapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function addUserDisplayEntry(map, name, entity = {}) {
  const rawName = stripUserDisplayNumber(name);
  if (!rawName) return;
  const key = normalizeName(rawName);
  if (!key) return;
  const next = {
    rawName,
    displayName: getDisplayNameWithNumber(rawName, entity)
  };
  const existing = map.get(key);
  if (!existing || next.rawName.length > existing.rawName.length) {
    map.set(key, next);
  }
}

function getKnownUserDisplayEntries() {
  const entries = new Map();
  const profile = getProfile();
  if (profile) {
    addUserDisplayEntry(entries, profile.name, profile);
    addUserDisplayEntry(entries, profile.athleteName, {
      uid: profile.linkedAthleteUid,
      id: profile.linkedAthleteId,
      name: profile.athleteName
    });
    addUserDisplayEntry(entries, profile.linkedCoachName, {
      uid: profile.linkedCoachUid,
      email: profile.linkedCoachEmail,
      name: profile.linkedCoachName
    });
  }
  [...ATHLETES, ...getCoachAthleteRecords(), ...getAthletesData(), ...parentPortalTeamCache].forEach((athlete) => {
    addUserDisplayEntry(entries, athlete?.name, athlete || {});
    addUserDisplayEntry(entries, athlete?.coachName, {
      uid: athlete?.coachUid,
      email: athlete?.coachEmail,
      name: athlete?.coachName
    });
  });
  [...adminUsersCache, ...coachDirectoryCache, ...coachParentApprovalsCache, ...messagesContactRows].forEach((user) => {
    addUserDisplayEntry(entries, user?.name, user || {});
    addUserDisplayEntry(entries, user?.athleteName, {
      uid: user?.linkedAthleteUid,
      id: user?.linkedAthleteId,
      name: user?.athleteName
    });
    addUserDisplayEntry(entries, user?.linkedCoachName, {
      uid: user?.linkedCoachUid,
      email: user?.linkedCoachEmail,
      name: user?.linkedCoachName
    });
  });
  messagesThreadRows.forEach((thread) => {
    (thread?.participantProfiles || []).forEach((participant) => {
      addUserDisplayEntry(entries, participant?.name, participant || {});
    });
  });
  return Array.from(entries.values()).sort((left, right) => right.rawName.length - left.rawName.length);
}

function decorateVisibleUserNames(root = document.body) {
  if (!root || typeof document === "undefined") return;
  const entries = getKnownUserDisplayEntries();
  if (!entries.length) return;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = node?.parentElement;
      if (!parent) return NodeFilter.FILTER_REJECT;
      if (!String(node.nodeValue || "").trim()) return NodeFilter.FILTER_REJECT;
      if (["SCRIPT", "STYLE", "TEXTAREA"].includes(parent.tagName)) return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  let currentNode = walker.nextNode();
  while (currentNode) {
    let nextValue = String(currentNode.nodeValue || "");
    entries.forEach((entry) => {
      const withNumberPattern = new RegExp(`${escapeRegExp(entry.rawName)}\\s+#\\d{4}\\b`, "g");
      nextValue = nextValue.replace(withNumberPattern, entry.rawName);
      const basePattern = new RegExp(`${escapeRegExp(entry.rawName)}(?!\\s+#\\d{4})`, "g");
      nextValue = nextValue.replace(basePattern, entry.displayName);
    });
    if (nextValue !== currentNode.nodeValue) {
      currentNode.nodeValue = nextValue;
    }
    currentNode = walker.nextNode();
  }
}

function queueUserNameDecoration(root = document.body) {
  if (userNameDecorationQueued || typeof window === "undefined") return;
  userNameDecorationQueued = true;
  requestAnimationFrame(() => {
    userNameDecorationQueued = false;
    decorateVisibleUserNames(root);
  });
}

function ensureUserNameDecorationObserver() {
  if (userNameDecorationObserver || typeof MutationObserver === "undefined" || !document?.body) return;
  userNameDecorationObserver = new MutationObserver(() => {
    queueUserNameDecoration(document.body);
  });
  userNameDecorationObserver.observe(document.body, {
    childList: true,
    subtree: true,
    characterData: true
  });
}

function uniqueNames(list) {
  const seen = new Set();
  const result = [];
  (list || []).forEach((name) => {
    const key = normalizeName(name);
    if (!key || seen.has(key)) return;
    seen.add(key);
    result.push(String(name).trim());
  });
  return result;
}

function normalizeUid(value) {
  return String(value || "").trim();
}

function isOfficialCoachEmail(value) {
  const email = normalizeEmail(value || "");
  return OFFICIAL_COACH_EMAILS.has(email) || email.endsWith("@united-wc.com");
}

function normalizeAthleteId(value, fallbackName = "") {
  const explicit = String(value || "").trim();
  return explicit || slugifyKey(fallbackName);
}

function resolveAthleteIdentity(input) {
  if (!input) {
    return {
      athleteId: "",
      athleteUid: "",
      athleteName: ""
    };
  }
  if (typeof input === "string") {
    const athlete = getCoachAthleteRecords().find((entry) => normalizeName(entry.name) === normalizeName(input))
      || ATHLETES.find((entry) => normalizeName(entry.name) === normalizeName(input))
      || null;
    if (athlete) {
      return {
        athleteId: normalizeAthleteId(athlete.id, athlete.name),
        athleteUid: normalizeUid(athlete.athleteUid),
        athleteName: athlete.name
      };
    }
    return {
      athleteId: normalizeAthleteId("", input),
      athleteUid: "",
      athleteName: String(input || "").trim()
    };
  }
  return {
    athleteId: normalizeAthleteId(input.id || input.athleteId, input.name || input.athleteName || ""),
    athleteUid: normalizeUid(input.athleteUid || input.user_id || input.uid),
    athleteName: String(input.athleteName || input.name || "").trim()
  };
}

function athleteIdentityMatches(record, input) {
  const left = resolveAthleteIdentity(record);
  const right = resolveAthleteIdentity(input);
  return Boolean(
    (left.athleteUid && right.athleteUid && left.athleteUid === right.athleteUid)
    || (left.athleteId && right.athleteId && left.athleteId === right.athleteId)
    || (left.athleteName && right.athleteName && normalizeName(left.athleteName) === normalizeName(right.athleteName))
  );
}

function getCoachAthleteRecordByIdentity(input) {
  return getCoachAthleteRecords().find((record) => athleteIdentityMatches(record, input)) || null;
}

function buildCoachAthleteSeedFromUser(user, {
  coachUid = "",
  coachName = "",
  coachEmail = ""
} = {}) {
  const athleteId = normalizeAthleteId(user?.linkedAthleteId || slugifyKey(user?.name || user?.email || ""), user?.name || user?.email || "");
  return {
    name: String(user?.name || user?.email || "Athlete").trim(),
    athleteUid: normalizeUid(user?.uid),
    athleteEmail: normalizeEmail(user?.email || ""),
    coachUid: String(user?.linkedCoachUid || coachUid || "").trim(),
    coachName: String(user?.linkedCoachName || coachName || "").trim(),
    coachEmail: normalizeEmail(user?.linkedCoachEmail || coachEmail || ""),
    currentWeight: String(user?.currentWeight || "").trim(),
    weight: String(user?.currentWeight || "").trim(),
    weightClass: String(user?.weightClass || "").trim(),
    style: String(user?.style || "").trim(),
    availability: "Active",
    preferred: String(user?.preferredMoves || "").trim(),
    notes: String(user?.notes || "").trim(),
    experienceYears: String(user?.experienceYears || "").trim(),
    level: String(user?.level || "").trim(),
    position: String(user?.position || "").trim(),
    strategy: String(user?.strategy || "").trim(),
    tags: normalizeSmartTags(user?.tags || []),
    createdAt: String(user?.createdAt || "").trim(),
    updatedAt: String(user?.updatedAt || user?.createdAt || "").trim(),
    id: athleteId
  };
}

function buildCoachAthleteRecordFromUser(user, coachMeta = {}) {
  const seed = buildCoachAthleteSeedFromUser(user, coachMeta);
  return normalizeCoachAthleteRecord(seed.id, seed);
}

function sortUsersByCreatedAt(users = []) {
  return [...users].sort((left, right) => {
    const leftCreatedAt = parseIsoTimestamp(left?.createdAt || left?.updatedAt || "");
    const rightCreatedAt = parseIsoTimestamp(right?.createdAt || right?.updatedAt || "");
    if (leftCreatedAt !== rightCreatedAt) {
      if (!leftCreatedAt) return 1;
      if (!rightCreatedAt) return -1;
      return leftCreatedAt - rightCreatedAt;
    }
    return String(left?.uid || "").localeCompare(String(right?.uid || ""));
  });
}

function pickPreferredAthleteUserForCoach(athlete, candidates = []) {
  const uniqueCandidates = [];
  const seen = new Set();
  candidates.forEach((candidate) => {
    if (!candidate?.uid || seen.has(candidate.uid)) return;
    seen.add(candidate.uid);
    uniqueCandidates.push(candidate);
  });
  if (!uniqueCandidates.length) return null;

  const canonicalAthleteUid = normalizeUid(athlete?.athleteUid);
  const athleteEmail = normalizeEmail(athlete?.athleteEmail || athlete?.email || "");
  const sortedCandidates = sortUsersByCreatedAt(uniqueCandidates);

  return sortedCandidates.find((candidate) => normalizeUid(candidate.uid) === canonicalAthleteUid)
    || sortedCandidates.find((candidate) => normalizeEmail(candidate.email) === athleteEmail)
    || sortedCandidates[0]
    || null;
}

function rankCoachLinkCandidate(candidate, authUser = getAuthUser()) {
  if (!candidate?.coach?.uid || !candidate?.athlete?.id) return -1;
  const athlete = candidate.athlete;
  const coach = candidate.coach;
  const authUid = normalizeUid(authUser?.id);
  const authEmail = normalizeEmail(authUser?.email || "");
  const coachEmail = normalizeEmail(coach.email || athlete.coachEmail || "");
  const athleteUid = normalizeUid(athlete.athleteUid);
  const athleteEmail = normalizeEmail(athlete.athleteEmail || "");
  const athleteUpdatedAt = parseIsoTimestamp(athlete.updatedAt || athlete.createdAt || "");
  const coachUpdatedAt = parseIsoTimestamp(coach.updatedAt || coach.createdAt || "");

  let score = 0;
  if (athleteUid && athleteUid === authUid) score += 1000;
  if (athleteEmail && athleteEmail === authEmail) score += 900;
  if (normalizeUid(athlete.coachUid) === normalizeUid(coach.uid)) score += 60;
  if (String(athlete.coachName || "").trim()) score += 25;
  if (coachEmail && isOfficialCoachEmail(coachEmail)) score += 200;
  if (String(athlete.coachEmail || "").trim() && isOfficialCoachEmail(athlete.coachEmail)) score += 80;
  if (athleteUid) score += 20;
  if (athleteEmail) score += 15;
  if (athleteUpdatedAt) score += Math.min(Math.floor(athleteUpdatedAt / 10000000), 50);
  if (coachUpdatedAt) score += Math.min(Math.floor(coachUpdatedAt / 10000000), 20);
  return score;
}

function filterLegacyAthleteNameRecords(records = []) {
  return records.filter((record) => {
    const athleteId = String(record?.athleteId || "").trim();
    const athleteUid = normalizeUid(record?.athleteUid);
    if (record?.athleteIds || record?.athleteUids) {
      return normalizedStringList(record.athleteIds || []).length === 0
        && normalizedStringList(record.athleteUids || []).length === 0;
    }
    const athleteName = String(record?.athleteName || record?.name || "").trim();
    return !athleteUid && Boolean(athleteName) && (!athleteId || athleteId === slugifyKey(athleteName));
  });
}

function defaultAudience() {
  return { all: false, athletes: [] };
}

function normalizeAudience(audience) {
  const base = defaultAudience();
  if (!audience || typeof audience !== "object") return base;
  return {
    all: audience.all === true,
    athletes: uniqueNames(audience.athletes)
  };
}

function normalizeCalendarEntry(entry) {
  if (Array.isArray(entry)) {
    return {
      items: entry.map((item) => String(item).trim()).filter(Boolean),
      audience: { all: true, athletes: [] }
    };
  }

  if (!entry || typeof entry !== "object") {
    return { items: [], audience: defaultAudience() };
  }

  const items = Array.isArray(entry.items)
    ? entry.items.map((item) => String(item).trim()).filter(Boolean)
    : [];
  const audience = normalizeAudience(entry.audience);
  return { items, audience };
}

function mergeCalendarEntries(a, b) {
  const left = normalizeCalendarEntry(a);
  const right = normalizeCalendarEntry(b);
  const items = [...left.items, ...right.items];
  const audience = {
    all: left.audience.all || right.audience.all,
    athletes: uniqueNames([...(left.audience.athletes || []), ...(right.audience.athletes || [])])
  };
  return { items, audience };
}

function migrateLegacyCalendarEvents(events) {
  if (!events || typeof events !== "object") return { events: {}, changed: false };
  const next = {};
  let changed = false;
  const weekStart = startOfWeek(new Date());

  Object.entries(events).forEach(([key, value]) => {
    if (isDateKey(key)) {
      const normalized = normalizeCalendarEntry(value);
      if (normalized.items.length) {
        next[key] = next[key] ? mergeCalendarEntries(next[key], normalized) : normalized;
      } else {
        changed = true;
      }
      return;
    }

    const dayIdx = Number.parseInt(key, 10);
    if (Number.isFinite(dayIdx) && dayIdx >= 0 && dayIdx < 7) {
      const dateKey = toDateKey(addDays(weekStart, dayIdx));
      const normalized = normalizeCalendarEntry(value);
      if (normalized.items.length) {
        next[dateKey] = next[dateKey] ? mergeCalendarEntries(next[dateKey], normalized) : normalized;
      }
      changed = true;
      return;
    }

    changed = true;
  });

  return { events: next, changed };
}

function getStoredCalendarEvents() {
  if (isCoachWorkspaceActive() && coachWorkspaceRealtimeUserId === getAuthUser()?.id) {
    return coachCalendarEntriesCache;
  }
  try {
    const raw = localStorage.getItem(CALENDAR_EVENTS_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    const { events, changed } = migrateLegacyCalendarEvents(parsed);
    if (changed) setStoredCalendarEvents(events);
    return events;
  } catch {
    return {};
  }
}

function setStoredCalendarEvents(events) {
  localStorage.setItem(CALENDAR_EVENTS_KEY, JSON.stringify(events || {}));
}

