async function syncAthleteProfileToCoachWorkspace(profile = getProfile(), authUser = getAuthUser()) {
  if (!isAthleteRole(profile?.role) || !authUser?.id) return;
  const coachUid = getAthleteLinkedCoachUid(profile);
  const athleteId = getAthleteLinkedAthleteId(profile);
  const athleteUid = getAthleteLinkedAthleteUid(profile, authUser) || authUser.id;
  const athletesRef = getCoachWorkspaceCollectionRef("athletes", coachUid);
  if (!coachUid || !athleteId || !athletesRef) return;

  const payload = stripUndefinedDeep({
    name: String(profile.name || authUser.email || "").trim(),
    athleteUid: String(athleteUid || "").trim(),
    athleteEmail: normalizeEmail(profile.email || authUser.email || ""),
    coachUid: String(coachUid || "").trim(),
    coachName: String(getAthleteLinkedCoachName(profile) || profile.linkedCoachName || "").trim(),
    coachEmail: normalizeEmail(profile.linkedCoachEmail || ""),
    age: String(profile.age || "").trim(),
    weight: String(profile.currentWeight || profile.weight || "").trim(),
    currentWeight: String(profile.currentWeight || profile.weight || "").trim(),
    weightClass: String(profile.weightClass || "").trim(),
    style: String(profile.style || "").trim(),
    level: String(profile.level || "").trim(),
    position: String(profile.position || "").trim(),
    strategy: String(profile.strategy || "").trim(),
    trainingRoutines: String(profile.trainingRoutines || "").trim(),
    trainingVolume: String(profile.trainingVolume || "").trim(),
    trainingFocus: String(profile.trainingFocus || "").trim(),
    preferredMoves: String(profile.preferredMoves || profile.preferred_moves || "").trim(),
    stance: String(profile.stance || "").trim(),
    questionnaireNotes: String(profile.questionnaireNotes || profile.notes || "").trim(),
    schoolName: String(profile.schoolName || "").trim(),
    clubName: String(profile.clubName || "").trim(),
    schoolGrade: String(profile.schoolGrade || "").trim(),
    favoritePosition: String(profile.favoritePosition || profile.position || "").trim(),
    psychTendency: String(profile.psychTendency || strategyToTendency(profile.strategy) || "").trim(),
    coachCues: String(profile.coachCues || "").trim(),
    archetype: String(profile.archetype || "").trim(),
    bodyType: String(profile.bodyType || "").trim(),
    offenseTop3: normalizeTopThree(profile.offenseTop3 || []),
    defenseTop3: normalizeTopThree(profile.defenseTop3 || []),
    setupsTop3: normalizeTopThree(profile.setupsTop3 || []),
    cornerCoachCues: normalizeTopThree(profile.cornerCoachCues || []),
    cueWords: normalizeTopThree(profile.cueWords || []),
    mentalReminders: normalizeTopThree(profile.mentalReminders || []),
    safetyWarnings: (Array.isArray(profile.safetyWarnings) ? profile.safetyWarnings : []).map((item) => String(item || "").trim()).filter(Boolean),
    physicalLimitations: (Array.isArray(profile.physicalLimitations) ? profile.physicalLimitations : []).map((item) => String(item || "").trim()).filter(Boolean),
    competitionCue: String(profile.competitionCue || "").trim(),
    pressureError: String(profile.pressureError || "").trim(),
    coachSignal: String(profile.coachSignal || "").trim(),
    tags: normalizeSmartTags(profile.tags || []),
    injuryNotes: String(profile.injuryNotes || "").trim(),
    cueNotes: String(profile.cueNotes || "").trim(),
    safeMoves: String(profile.safeMoves || "").trim(),
    riskyMoves: String(profile.riskyMoves || "").trim(),
    strategyA: String(profile.strategyA || "").trim(),
    strategyB: String(profile.strategyB || "").trim(),
    strategyC: String(profile.strategyC || "").trim(),
    challenges: (Array.isArray(profile.challenges) ? profile.challenges : [
      profile.challengeOne,
      profile.challengeTwo,
      profile.challengeThree
    ]).map((item) => String(item || "").trim()).filter(Boolean),
    challengeOne: String(profile.challengeOne || profile.challenges?.[0] || "").trim(),
    challengeTwo: String(profile.challengeTwo || profile.challenges?.[1] || "").trim(),
    challengeThree: String(profile.challengeThree || profile.challenges?.[2] || "").trim(),
    resultsHistory: String(profile.resultsHistory || "").trim(),
    international: String(profile.international || "").trim(),
    internationalEvents: String(profile.internationalEvents || "").trim(),
    internationalYears: String(profile.internationalYears || "").trim(),
    techniques: {
      neutral: Array.isArray(profile.techniques?.neutral) ? profile.techniques.neutral.map((item) => String(item || "").trim()).filter(Boolean) : [],
      top: Array.isArray(profile.techniques?.top) ? profile.techniques.top.map((item) => String(item || "").trim()).filter(Boolean) : [],
      bottom: Array.isArray(profile.techniques?.bottom) ? profile.techniques.bottom.map((item) => String(item || "").trim()).filter(Boolean) : [],
      defense: Array.isArray(profile.techniques?.defense) ? profile.techniques.defense.map((item) => String(item || "").trim()).filter(Boolean) : [],
      neutralOther: String(profile.techniques?.neutralOther || "").trim(),
      topOther: String(profile.techniques?.topOther || "").trim(),
      bottomOther: String(profile.techniques?.bottomOther || "").trim(),
      defenseOther: String(profile.techniques?.defenseOther || "").trim()
    },
    defaultTechniques: {
      leadLeg: String(profile.defaultTechniques?.leadLeg || "").trim(),
      leftAttack: String(profile.defaultTechniques?.leftAttack || "").trim(),
      rightAttack: String(profile.defaultTechniques?.rightAttack || "").trim(),
      preferredTies: String(profile.defaultTechniques?.preferredTies || "").trim(),
      miscNotes: String(profile.defaultTechniques?.miscNotes || "").trim()
    },
    availability: String(profile.availability || "Available").trim(),
    preferred: String(profile.preferred || profile.trainingFocus || "").trim(),
    history: String(profile.history || "").trim(),
    notes: String(profile.notes || profile.resultsHistory || "").trim(),
    updatedAt: getFirestoreServerTimestamp()
  });

  await withTimeout(
    athletesRef.doc(athleteId).set(payload, { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_athlete_profile_workspace_sync_timeout"
  );
}

function getCompetitionRecordsForContext() {
  const role = normalizeAuthRole(getProfile()?.role);
  if (role === "coach" || role === "admin") {
    if (coachCompetitionsCache.length) return coachWorkspaceSortByUpdated(coachCompetitionsCache);
    if (athletePortalCompetitionsCache.length) return coachWorkspaceSortByUpdated(athletePortalCompetitionsCache);
  } else if (role === "athlete") {
    if (athletePortalCompetitionsCache.length) return coachWorkspaceSortByUpdated(athletePortalCompetitionsCache);
    if (coachCompetitionsCache.length) return coachWorkspaceSortByUpdated(coachCompetitionsCache);
  } else {
    if (coachCompetitionsCache.length) return coachWorkspaceSortByUpdated(coachCompetitionsCache);
    if (athletePortalCompetitionsCache.length) return coachWorkspaceSortByUpdated(athletePortalCompetitionsCache);
  }
  if (PUBLISH_READY_MODE) return [];
  return getSeedCoachCompetitionRecords().map((record) => normalizeCoachCompetitionRecord(record.id, record));
}

function getCompetitionStatus(competition, todayKey = getCurrentAppDateKey()) {
  if (!competition) return "future";
  const startKey = isDateKey(competition.startDateKey) ? competition.startDateKey : "";
  const endKey = isDateKey(competition.endDateKey)
    ? competition.endDateKey
    : (startKey || "");
  if (!startKey && !endKey) return "future";
  if (!startKey && endKey) {
    return todayKey <= endKey ? "current" : "past";
  }
  if (startKey && !endKey) {
    return todayKey < startKey ? "future" : "current";
  }
  if (todayKey < startKey) return "future";
  if (todayKey > endKey) return "past";
  return "current";
}

function getCompetitionDateRangeLabel(competition) {
  if (!competition) return currentLang === "es" ? "Sin fecha" : "No date";
  const startKey = isDateKey(competition.startDateKey) ? competition.startDateKey : "";
  const endKey = isDateKey(competition.endDateKey) ? competition.endDateKey : "";
  if (startKey && endKey && startKey !== endKey) {
    return `${formatPlanDateLabel(startKey)} - ${formatPlanDateLabel(endKey)}`;
  }
  if (startKey) return formatPlanDateLabel(startKey);
  if (endKey) return formatPlanDateLabel(endKey);
  return currentLang === "es" ? "Sin fecha" : "No date";
}

function sortCompetitionsByDate(records = []) {
  return [...records].sort((left, right) => {
    const leftStart = left.startDateKey || left.endDateKey || "9999-99-99";
    const rightStart = right.startDateKey || right.endDateKey || "9999-99-99";
    if (leftStart !== rightStart) return leftStart.localeCompare(rightStart);
    return String(left.name || "").localeCompare(String(right.name || ""), undefined, { sensitivity: "base" });
  });
}

function getCompetitionTimeline(records = []) {
  const todayKey = getCurrentAppDateKey();
  const sorted = sortCompetitionsByDate(records);
  const current = sorted.filter((record) => getCompetitionStatus(record, todayKey) === "current");
  const past = sorted
    .filter((record) => getCompetitionStatus(record, todayKey) === "past")
    .sort((left, right) => {
      const leftEnd = left.endDateKey || left.startDateKey || "";
      const rightEnd = right.endDateKey || right.startDateKey || "";
      return rightEnd.localeCompare(leftEnd);
    });
  const future = sorted.filter((record) => getCompetitionStatus(record, todayKey) === "future");
  return { current, past, future };
}

function getCompetitionAthleteRoster(competition) {
  if (!competition) return [];
  const athletes = getAthletesData();
  const idSet = new Set((competition.athleteIds || []).map((value) => String(value || "").trim()).filter(Boolean));
  const uidSet = new Set((competition.athleteUids || []).map((value) => String(value || "").trim()).filter(Boolean));
  const nameSet = new Set((competition.athleteNames || []).map((value) => normalizeName(value)).filter(Boolean));
  const roster = [];
  const seenKeys = new Set();

  function pushEntry(entry) {
    const athleteName = String(entry?.name || entry?.athleteName || "").trim();
    const explicitId = String(entry?.id || entry?.athleteId || "").trim();
    const athleteId = explicitId || (athleteName ? normalizeAthleteId("", athleteName) : "");
    const athleteUid = normalizeUid(entry?.athleteUid || entry?.uid);
    const uniqueKey = athleteUid || athleteId || normalizeName(athleteName);
    if (!uniqueKey || seenKeys.has(uniqueKey)) return;
    seenKeys.add(uniqueKey);
    roster.push({
      athleteId,
      athleteUid,
      athleteName: athleteName || (currentLang === "es" ? "Atleta" : "Athlete"),
      availability: entry?.availability || "",
      level: entry?.level || ""
    });
  }

  athletes.forEach((athlete) => {
    const athleteId = normalizeAthleteId(athlete.id, athlete.name);
    const athleteUid = normalizeUid(athlete.athleteUid);
    const athleteName = normalizeName(athlete.name);
    if (
      (athleteId && idSet.has(athleteId))
      || (athleteUid && uidSet.has(athleteUid))
      || (athleteName && nameSet.has(athleteName))
    ) {
      pushEntry(athlete);
    }
  });

  (competition.athleteIds || []).forEach((athleteId, index) => {
    const athlete = getCoachAthleteRecordByIdentity({ athleteId: String(athleteId || "").trim() });
    const fallbackName = competition.athleteNames?.[index] || athlete?.name || "";
    pushEntry({
      id: athleteId,
      athleteUid: athlete?.athleteUid || competition.athleteUids?.[index] || "",
      name: fallbackName || athlete?.name || "",
      availability: athlete?.availability || "",
      level: athlete?.level || ""
    });
  });

  (competition.athleteUids || []).forEach((athleteUid, index) => {
    const athlete = getCoachAthleteRecordByIdentity({ athleteUid: String(athleteUid || "").trim() });
    pushEntry({
      id: athlete?.id || competition.athleteIds?.[index] || "",
      athleteUid,
      name: athlete?.name || competition.athleteNames?.[index] || "",
      availability: athlete?.availability || "",
      level: athlete?.level || ""
    });
  });

  (competition.athleteNames || []).forEach((athleteName) => {
    pushEntry({
      name: athleteName
    });
  });

  return roster;
}

function competitionIncludesAthlete(competition, athleteInput) {
  if (!competition || !athleteInput) return false;
  const identity = resolveAthleteIdentity(athleteInput);
  const idSet = new Set((competition.athleteIds || []).map((value) => String(value || "").trim()).filter(Boolean));
  const uidSet = new Set((competition.athleteUids || []).map((value) => String(value || "").trim()).filter(Boolean));
  const nameSet = new Set((competition.athleteNames || []).map((value) => normalizeName(value)).filter(Boolean));
  if (identity.athleteId && idSet.has(identity.athleteId)) return true;
  if (identity.athleteUid && uidSet.has(identity.athleteUid)) return true;
  if (identity.athleteName && nameSet.has(normalizeName(identity.athleteName))) return true;
  return false;
}

async function createCoachCompetitionRecord(payload = {}) {
  const competitionsRef = getCoachWorkspaceCollectionRef("competitions");
  if (!competitionsRef) {
    throw new Error("competition_store_unavailable");
  }
  const name = String(payload.name || "").trim();
  const startDateKey = isDateKey(payload.startDateKey) ? payload.startDateKey : getCurrentAppDateKey();
  const endDateKey = isDateKey(payload.endDateKey) ? payload.endDateKey : startDateKey;
  const location = String(payload.location || "").trim();
  const style = String(payload.style || "").trim();
  const description = String(payload.description || "").trim();
  const organizer = String(payload.organizer || "").trim();
  const note = String(payload.note || "").trim();
  if (!name) {
    throw new Error("competition_name_required");
  }
  const docId = `${slugifyKey(name)}-${Date.now().toString(36)}`;
  await withTimeout(
    competitionsRef.doc(docId).set(stripUndefinedDeep({
      name,
      startDateKey,
      endDateKey,
      location,
      style,
      description,
      organizer,
      note,
      allowSelfJoin: payload.allowSelfJoin !== false,
      allowCoachInvite: payload.allowCoachInvite !== false,
      athleteNames: [],
      athleteIds: [],
      athleteUids: [],
      createdBy: String(getAuthUser()?.id || "").trim(),
      updatedBy: String(getAuthUser()?.id || "").trim(),
      createdAt: getFirestoreServerTimestamp(),
      updatedAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_competition_create_timeout"
  );
  selectedCompetitionId = docId;
}

async function updateCoachCompetitionRoster(competition, athleteIdentity, { remove = false, workspaceUid = "" } = {}) {
  const competitionsRef = getCoachWorkspaceCollectionRef("competitions", workspaceUid || getAuthUser()?.id);
  if (!competitionsRef || !competition?.id) {
    throw new Error("competition_store_unavailable");
  }
  const identityList = (Array.isArray(athleteIdentity) ? athleteIdentity : [athleteIdentity])
    .map((entry) => resolveAthleteIdentity(entry))
    .filter((entry) => entry.athleteId || entry.athleteUid || entry.athleteName);
  if (!identityList.length) {
    throw new Error("competition_athlete_required");
  }
  let nextIds = (competition.athleteIds || []).map((value) => String(value || "").trim()).filter(Boolean);
  let nextUids = (competition.athleteUids || []).map((value) => String(value || "").trim()).filter(Boolean);
  let nextNames = uniqueNames(competition.athleteNames || []);

  identityList.forEach((identity) => {
    const normalizedName = String(identity.athleteName || "").trim();
    const normalizedId = String(identity.athleteId || "").trim();
    const normalizedUid = String(identity.athleteUid || "").trim();
    const rosterMatch = getCompetitionAthleteRoster(competition).find((entry) => athleteIdentityMatches(entry, identity)) || null;
    const targetName = String(rosterMatch?.athleteName || normalizedName).trim();
    const targetId = String(rosterMatch?.athleteId || normalizedId).trim();
    const targetUid = String(rosterMatch?.athleteUid || normalizedUid).trim();

    if (remove) {
      nextIds = nextIds.filter((value) => value !== targetId && value !== normalizedId);
      nextUids = nextUids.filter((value) => value !== targetUid && value !== normalizedUid);
      nextNames = nextNames.filter((value) => normalizeName(value) !== normalizeName(targetName || normalizedName));
    } else {
      nextIds = uniqueNames([...nextIds, targetId || normalizedId]).filter(Boolean);
      nextUids = uniqueNames([...nextUids, targetUid || normalizedUid]).filter(Boolean);
      nextNames = uniqueNames([...nextNames, targetName || normalizedName]).filter(Boolean);
    }
  });

  await withTimeout(
    competitionsRef.doc(competition.id).set(stripUndefinedDeep({
      athleteIds: nextIds,
      athleteUids: nextUids,
      athleteNames: nextNames,
      updatedBy: String(getAuthUser()?.id || "").trim(),
      updatedAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_competition_roster_update_timeout"
  );
}

function renderCompetitionManager(selectedProfile = null) {
  if (!competitionManager || !competitionCurrentCard || !competitionPastList || !competitionFutureList || !competitionDetailCard) return;
  if (competitionPastHeading) {
    competitionPastHeading.textContent = currentLang === "es" ? "Competencias pasadas" : "Past Competitions";
  }
  if (competitionFutureHeading) {
    competitionFutureHeading.textContent = currentLang === "es" ? "Competencias futuras" : "Future Competitions";
  }
  const canEdit = isCoachWorkspaceActive();
  if (competitionPreviewChip) {
    competitionPreviewChip.textContent = canEdit
      ? (currentLang === "es" ? "Vista entrenador" : "Coach view")
      : (currentLang === "es" ? "Vista atleta" : "Athlete view");
  }
  const records = getCompetitionRecordsForContext();
  const timeline = getCompetitionTimeline(records);
  const lookup = new Map(records.map((record) => [record.id, record]));
  if (!selectedCompetitionId || !lookup.has(selectedCompetitionId)) {
    selectedCompetitionId = timeline.current[0]?.id || timeline.future[0]?.id || timeline.past[0]?.id || "";
  }
  const selectedCompetition = lookup.get(selectedCompetitionId) || null;
  const currentCompetition = timeline.current[0] || null;
  const activeAthlete = selectedProfile || (isAthleteRole(getProfile()?.role) ? (getAthletePortalLinkedAthlete() || getProfile()) : null);
  const activeAthleteName = String(activeAthlete?.name || "").trim();
  const athleteFromRoster = getSelectedCoachAthleteRecord();
  const viewerProfile = getProfile();
  const athleteCoachUid = getAthleteLinkedCoachUid(viewerProfile);

  competitionCurrentCard.innerHTML = `
    <div class="competition-current-top">
      <h3>${currentLang === "es" ? "Competencia actual" : "Current competition"}</h3>
      ${canEdit ? `<button type="button" id="competitionToggleCreateBtn">${competitionCreateOpen ? (currentLang === "es" ? "Cancelar" : "Cancel") : (currentLang === "es" ? "Nueva competencia" : "New competition")}</button>` : ""}
    </div>
    ${currentCompetition
      ? `
        <p class="competition-current-name">${escapeHtml(currentCompetition.name || (currentLang === "es" ? "Sin nombre" : "Untitled competition"))}</p>
        <p class="small competition-current-meta">${escapeHtml(getCompetitionDateRangeLabel(currentCompetition))}${currentCompetition.location ? ` • ${escapeHtml(currentCompetition.location)}` : ""}</p>
        ${currentCompetition.style ? `<p class="small competition-current-meta">${escapeHtml(currentCompetition.style)}</p>` : ""}
        ${currentCompetition.description ? `<p class="small muted">${escapeHtml(currentCompetition.description)}</p>` : ""}
      `
      : `
        <div class="competition-empty">${currentLang === "es" ? "No hay una competencia activa ahora mismo." : "No active competition right now."}</div>
      `
    }
    ${(canEdit && competitionCreateOpen) ? `
      <div class="competition-create-grid">
        <input id="competitionCreateNameInput" type="text" placeholder="${currentLang === "es" ? "Nombre de la competencia" : "Competition name"}">
        <input id="competitionCreateStartInput" type="date" value="${getCurrentAppDateKey()}">
        <input id="competitionCreateEndInput" type="date" value="${getCurrentAppDateKey()}">
        <input id="competitionCreateLocationInput" type="text" placeholder="${currentLang === "es" ? "Lugar (opcional)" : "Location (optional)"}">
        <input id="competitionCreateStyleInput" type="text" placeholder="${currentLang === "es" ? "Estilo (Freestyle / Greco)" : "Style (Freestyle / Greco)"}">
        <input id="competitionCreateOrganizerInput" type="text" placeholder="${currentLang === "es" ? "Organizador (opcional)" : "Organizer (optional)"}">
        <input id="competitionCreateNoteInput" type="text" placeholder="${currentLang === "es" ? "Nota rapida (opcional)" : "Quick note (optional)"}">
        <textarea id="competitionCreateDescriptionInput" rows="3" placeholder="${currentLang === "es" ? "Descripcion de la competencia" : "Competition description"}"></textarea>
      </div>
      <div class="row">
        <button type="button" class="primary" id="competitionCreateSaveBtn">${currentLang === "es" ? "Guardar competencia" : "Save competition"}</button>
      </div>
    ` : ""}
  `;

  const renderTimelineList = (target, items, emptyLabel) => {
    target.innerHTML = "";
    if (!items.length) {
      target.innerHTML = `<div class="competition-empty">${emptyLabel}</div>`;
      return;
    }
    items.forEach((item) => {
      const button = document.createElement("button");
      button.type = "button";
      button.className = "competition-row";
      if (item.id === selectedCompetitionId) {
        button.classList.add("active");
      }
      button.innerHTML = `
        <span class="competition-row-name">${escapeHtml(item.name || (currentLang === "es" ? "Sin nombre" : "Untitled competition"))}</span>
        <span class="competition-row-meta">${escapeHtml(getCompetitionDateRangeLabel(item))}${item.location ? ` • ${escapeHtml(item.location)}` : ""}</span>
        ${item.style ? `<span class="competition-row-meta">${escapeHtml(item.style)}</span>` : ""}
      `;
      button.addEventListener("click", () => {
        selectedCompetitionId = item.id;
        renderCompetitionPreview(selectedProfile);
      });
      target.appendChild(button);
    });
  };

  renderTimelineList(
    competitionPastList,
    timeline.past,
    currentLang === "es" ? "Sin competencias pasadas." : "No past competitions."
  );
  renderTimelineList(
    competitionFutureList,
    timeline.future,
    currentLang === "es" ? "Sin competencias futuras." : "No future competitions."
  );

  if (!selectedCompetition) {
    competitionDetailCard.innerHTML = `<h3>${currentLang === "es" ? "Atletas del torneo" : "Tournament athletes"}</h3><div class="competition-empty">${currentLang === "es" ? "Selecciona o crea una competencia para ver atletas registrados." : "Select or create a competition to view registered athletes."}</div>`;
  } else {
    const roster = getCompetitionAthleteRoster(selectedCompetition);
    const athleteAlreadyJoined = activeAthlete ? competitionIncludesAthlete(selectedCompetition, activeAthlete) : false;
    const canAthleteSelfJoin = !canEdit
      && isAthleteRole(viewerProfile?.role)
      && Boolean(activeAthlete)
      && selectedCompetition.allowSelfJoin !== false
      && !athleteAlreadyJoined;
    const rosterHtml = roster.length
      ? roster.map((entry) => {
        const isActiveAthlete = activeAthleteName && normalizeName(entry.athleteName) === normalizeName(activeAthleteName);
        const metaParts = [entry.level, entry.availability].filter(Boolean).join(" • ");
        return `
          <div class="competition-athlete-row${isActiveAthlete ? " competition-athlete-row-athlete" : ""}">
            <div>
              <strong>${escapeHtml(entry.athleteName)}</strong>
              <div class="small">${escapeHtml(metaParts || (currentLang === "es" ? "Registro activo" : "Registered"))}${isActiveAthlete ? ` • ${currentLang === "es" ? "tu" : "you"}` : ""}</div>
            </div>
            ${canEdit ? `<button type="button" class="ghost competition-remove-athlete-btn" data-athlete-id="${escapeHtml(entry.athleteId)}" data-athlete-uid="${escapeHtml(entry.athleteUid)}" data-athlete-name="${escapeHtml(entry.athleteName)}">${currentLang === "es" ? "Quitar" : "Remove"}</button>` : ""}
          </div>
        `;
      }).join("")
      : `<div class="competition-empty">${currentLang === "es" ? "Todavia no hay atletas registrados en esta competencia." : "No athletes registered in this competition yet."}</div>`;
    const availableAthletes = getAthletesData()
      .filter((athlete) => !competitionIncludesAthlete(selectedCompetition, athlete))
      .sort((left, right) => String(left.name || "").localeCompare(String(right.name || ""), undefined, { sensitivity: "base" }));
    const selectedFromAthletesLabel = athleteFromRoster?.name
      ? `${currentLang === "es" ? "Agregar seleccionado" : "Add selected"}: ${athleteFromRoster.name}`
      : (currentLang === "es" ? "Agregar atleta seleccionado" : "Add selected athlete");
    const pickerCards = availableAthletes.length
      ? availableAthletes.map((athlete) => {
        const meta = [
          athlete.weightClass ? `${currentLang === "es" ? "Cat." : "Class"} ${athlete.weightClass}` : "",
          athlete.level ? getLevelLabel(athlete.level) : "",
          athlete.availability || ""
        ].filter(Boolean).join(" • ");
        return `
          <label class="competition-picker-item" data-search="${escapeHtml(normalizeName(athlete.name))}">
            <input type="checkbox" class="competition-picker-check" value="${escapeHtml(athlete.name)}">
            <span class="competition-picker-copy">
              <strong>${escapeHtml(athlete.name)}</strong>
              <span class="small">${escapeHtml(meta || (currentLang === "es" ? "Disponible para registrar" : "Ready to register"))}</span>
            </span>
          </label>
        `;
      }).join("")
      : `<div class="competition-empty">${currentLang === "es" ? "No hay atletas pendientes para agregar." : "No remaining athletes to add."}</div>`;
    competitionDetailCard.innerHTML = `
      <h3>${escapeHtml(selectedCompetition.name || (currentLang === "es" ? "Competencia" : "Competition"))}</h3>
      <p class="small muted">${escapeHtml(getCompetitionDateRangeLabel(selectedCompetition))}${selectedCompetition.location ? ` • ${escapeHtml(selectedCompetition.location)}` : ""}</p>
      ${selectedCompetition.style ? `<p class="small muted">${escapeHtml(selectedCompetition.style)}</p>` : ""}
      ${selectedCompetition.organizer ? `<p class="small muted">${escapeHtml(selectedCompetition.organizer)}</p>` : ""}
      ${selectedCompetition.description ? `<p class="small">${escapeHtml(selectedCompetition.description)}</p>` : ""}
      ${selectedCompetition.note ? `<p class="small muted">${escapeHtml(selectedCompetition.note)}</p>` : ""}
      <div class="competition-athlete-list">${rosterHtml}</div>
      ${canEdit ? `
        <div class="competition-picker-shell">
          <div class="competition-picker-header">
            <h4>${currentLang === "es" ? "Selecciona atletas para agregar" : "Select athletes to add"}</h4>
            <div class="competition-picker-header-actions">
              <button type="button" id="competitionSelectAllBtn">${currentLang === "es" ? "Seleccionar todos" : "Select all"}</button>
              <button type="button" class="ghost" id="competitionClearSelectionBtn">${currentLang === "es" ? "Limpiar" : "Clear"}</button>
            </div>
          </div>
          <input id="competitionAthleteSearchInput" type="text" placeholder="${currentLang === "es" ? "Buscar atleta..." : "Search athlete..."}">
          <div class="competition-picker-grid" id="competitionAthletePickerGrid">${pickerCards}</div>
          <div class="competition-roster-tools">
            <button type="button" class="primary" id="competitionAddSelectedAthletesBtn">${currentLang === "es" ? "Invitar seleccionados (0)" : "Invite selected (0)"}</button>
            <button type="button" id="competitionAddSelectedBtn">${escapeHtml(selectedFromAthletesLabel)}</button>
          </div>
        </div>
      ` : ""}
      ${canAthleteSelfJoin ? `
        <div class="competition-roster-tools competition-roster-tools-single">
          <button type="button" class="primary" id="competitionAthleteJoinBtn">${currentLang === "es" ? "Agregarme a esta competencia" : "Add me to this competition"}</button>
        </div>
      ` : ""}
    `;

    if (canEdit) {
      const searchInput = document.getElementById("competitionAthleteSearchInput");
      const selectAllBtn = document.getElementById("competitionSelectAllBtn");
      const clearSelectionBtn = document.getElementById("competitionClearSelectionBtn");
      const addManyBtn = document.getElementById("competitionAddSelectedAthletesBtn");
      const addSelectedBtn = document.getElementById("competitionAddSelectedBtn");
      const pickerGrid = document.getElementById("competitionAthletePickerGrid");
      const pickerItems = Array.from(pickerGrid?.querySelectorAll(".competition-picker-item") || []);
      const pickerChecks = Array.from(pickerGrid?.querySelectorAll(".competition-picker-check") || []);

      const getCheckedNames = () => pickerChecks
        .filter((input) => input.checked)
        .map((input) => String(input.value || "").trim())
        .filter(Boolean);

      const updateAddManyButtonLabel = () => {
        if (!addManyBtn) return;
        const count = getCheckedNames().length;
        addManyBtn.textContent = currentLang === "es"
          ? `Invitar seleccionados (${count})`
          : `Invite selected (${count})`;
        addManyBtn.disabled = count === 0;
      };

      const applyPickerFilter = () => {
        const query = normalizeName(searchInput?.value || "");
        pickerItems.forEach((item) => {
          const haystack = String(item.dataset.search || "").trim();
          item.classList.toggle("hidden", Boolean(query) && !haystack.includes(query));
        });
      };

      pickerChecks.forEach((input) => {
        input.addEventListener("change", () => {
          updateAddManyButtonLabel();
        });
      });

      searchInput?.addEventListener("input", () => {
        applyPickerFilter();
      });

      selectAllBtn?.addEventListener("click", () => {
        const visibleChecks = pickerChecks.filter((input) => !input.closest(".hidden"));
        const shouldSelectAll = visibleChecks.some((input) => !input.checked);
        visibleChecks.forEach((input) => {
          input.checked = shouldSelectAll;
        });
        updateAddManyButtonLabel();
      });

      clearSelectionBtn?.addEventListener("click", () => {
        pickerChecks.forEach((input) => {
          input.checked = false;
        });
        updateAddManyButtonLabel();
      });

      addManyBtn?.addEventListener("click", async () => {
        const selectedNames = getCheckedNames();
        if (!selectedNames.length) {
          toast(currentLang === "es" ? "Selecciona al menos un atleta." : "Select at least one athlete.");
          return;
        }
        const athletesToAdd = selectedNames
          .map((name) => getCoachAthleteRecordByIdentity(name) || getAthletesData().find((item) => item.name === name) || null)
          .filter(Boolean);
        if (!athletesToAdd.length) return;
        try {
          addManyBtn.disabled = true;
          await updateCoachCompetitionRoster(selectedCompetition, athletesToAdd, { remove: false });
          toast(currentLang === "es"
            ? `${athletesToAdd.length} atleta(s) agregados a la competencia.`
            : `${athletesToAdd.length} athlete(s) added to competition.`);
        } catch (err) {
          console.warn("Competition multi-add failed", err);
          toast(currentLang === "es" ? "No se pudieron agregar los atletas." : "Could not add selected athletes.");
        } finally {
          updateAddManyButtonLabel();
        }
      });

      addSelectedBtn?.addEventListener("click", async () => {
        const athlete = athleteFromRoster || null;
        if (!athlete) {
          toast(currentLang === "es" ? "Selecciona un atleta en la ruta Athletes." : "Select an athlete in the Athletes route first.");
          return;
        }
        try {
          await updateCoachCompetitionRoster(selectedCompetition, athlete, { remove: false });
          toast(currentLang === "es" ? "Atleta agregado a la competencia." : "Athlete added to competition.");
        } catch (err) {
          console.warn("Competition selected athlete add failed", err);
          toast(currentLang === "es" ? "No se pudo agregar el atleta." : "Could not add athlete.");
        }
      });
      competitionDetailCard.querySelectorAll(".competition-remove-athlete-btn").forEach((button) => {
        button.addEventListener("click", async () => {
          const athleteId = String(button.dataset.athleteId || "").trim();
          const athleteUid = String(button.dataset.athleteUid || "").trim();
          const athleteName = String(button.dataset.athleteName || "").trim();
          try {
            await updateCoachCompetitionRoster(selectedCompetition, { athleteId, athleteUid, athleteName }, { remove: true });
            toast(currentLang === "es" ? "Atleta removido de la competencia." : "Athlete removed from competition.");
          } catch (err) {
            console.warn("Competition roster remove failed", err);
            toast(currentLang === "es" ? "No se pudo remover el atleta." : "Could not remove athlete.");
          }
        });
      });

      applyPickerFilter();
      updateAddManyButtonLabel();
    }

    const athleteJoinBtn = document.getElementById("competitionAthleteJoinBtn");
    athleteJoinBtn?.addEventListener("click", async () => {
      if (!activeAthlete) {
        toast(currentLang === "es" ? "No se pudo detectar el atleta actual." : "Could not detect current athlete.");
        return;
      }
      try {
        athleteJoinBtn.disabled = true;
        await updateCoachCompetitionRoster(
          selectedCompetition,
          activeAthlete,
          { remove: false, workspaceUid: athleteCoachUid || selectedCompetition.createdBy || "" }
        );
        toast(currentLang === "es" ? "Te agregaste a la competencia." : "You joined the competition.");
      } catch (err) {
        console.warn("Athlete self-join failed", err);
        toast(currentLang === "es" ? "No se pudo completar el registro." : "Could not complete competition registration.");
      } finally {
        athleteJoinBtn.disabled = false;
      }
    });
  }

  const toggleCreateBtn = document.getElementById("competitionToggleCreateBtn");
  toggleCreateBtn?.addEventListener("click", () => {
    competitionCreateOpen = !competitionCreateOpen;
    renderCompetitionPreview(selectedProfile);
  });
  const createSaveBtn = document.getElementById("competitionCreateSaveBtn");
  createSaveBtn?.addEventListener("click", async () => {
    const name = String(document.getElementById("competitionCreateNameInput")?.value || "").trim();
    const startDateKey = String(document.getElementById("competitionCreateStartInput")?.value || "").trim();
    const endDateKey = String(document.getElementById("competitionCreateEndInput")?.value || "").trim();
    const location = String(document.getElementById("competitionCreateLocationInput")?.value || "").trim();
    const style = String(document.getElementById("competitionCreateStyleInput")?.value || "").trim();
    const organizer = String(document.getElementById("competitionCreateOrganizerInput")?.value || "").trim();
    const note = String(document.getElementById("competitionCreateNoteInput")?.value || "").trim();
    const description = String(document.getElementById("competitionCreateDescriptionInput")?.value || "").trim();
    if (!name || !isDateKey(startDateKey) || !isDateKey(endDateKey)) {
      toast(currentLang === "es" ? "Completa nombre, fecha inicio y fecha fin." : "Provide competition name, start date, and end date.");
      return;
    }
    try {
      await createCoachCompetitionRecord({
        name,
        startDateKey,
        endDateKey,
        location,
        style,
        organizer,
        note,
        description
      });
      competitionCreateOpen = false;
      toast(currentLang === "es" ? "Competencia guardada." : "Competition saved.");
    } catch (err) {
      console.warn("Competition create failed", err);
      toast(currentLang === "es" ? "No se pudo guardar la competencia." : "Could not save competition.");
    }
  });
}

function buildCompetitionPreview(profile) {
  if (!profile) return [];
  const athleteIdentity = resolveAthleteIdentity(profile);
  const na = currentLang === "es" ? "N/D" : "N/A";
  const none = currentLang === "es" ? "Ninguna" : "None";
  const unknown = currentLang === "es" ? "Desconocido" : "Unknown";
  const yearsLabel = currentLang === "es" ? "anos" : "years";
  const style = profile.style
    ? translateOptionValue("aStyle", profile.style) || translateValue(profile.style)
    : na;
  const weight = profile.currentWeight || na;
  const weightClass = profile.weightClass || na;
  const years = profile.years || profile.experienceYears || na;
  const level = getLevelLabel(profile.level) || na;
  const position = profile.position ? translateOptionValue("pPosition", profile.position) : na;
  const strategy = profile.strategy ? translateOptionValue("pStrategy", profile.strategy) : na;
  const intl = profile.international ? translateOptionValue("pInternational", profile.international) : na;
  const coachCues = profile.coachCues ? translateOptionValue("pCoachCues", profile.coachCues) : na;
  const neutralList = translateTechniqueList(profile.techniques?.neutral);
  const topList = translateTechniqueList(profile.techniques?.top);
  const bottomList = translateTechniqueList(profile.techniques?.bottom);
  const defenseList = translateTechniqueList(profile.techniques?.defense);
  const tendencyKey = profile.psychTendency || tendencyFallback(profile.strategy);
  const tendency = translateOptionValue("aPsychTendency", tendencyKey) || translateValue(tendencyKey) || na;
  const favoritePosition = translateOptionValue("aFavoritePosition", profile.favoritePosition || profile.position) || na;
  const offense = translateTechniqueList(profile.offenseTop3 || []).join(", ") || na;
  const defense = translateTechniqueList(profile.defenseTop3 || []).join(", ") || na;
  const tags = normalizeSmartTags(profile.tags).map((tag) => formatSmartTag(tag)).join(" • ") || na;
  const strategyPlans = [profile.strategyA, profile.strategyB, profile.strategyC].filter(Boolean);
  const latestPlan = athleteIdentity.athleteId || athleteIdentity.athleteUid || athleteIdentity.athleteName
    ? getLatestCoachPlanForAthlete(athleteIdentity)
    : null;
  const liveAssignments = athleteIdentity.athleteId || athleteIdentity.athleteUid || athleteIdentity.athleteName
    ? getPlanAssignmentsForAthlete(athleteIdentity)
    : [];
  const latestJournal = athleteIdentity.athleteId || athleteIdentity.athleteUid || athleteIdentity.athleteName
    ? getLatestCoachJournalRecord(athleteIdentity)
    : null;
  const latestNotes = athleteIdentity.athleteId || athleteIdentity.athleteUid || athleteIdentity.athleteName
    ? getCoachNoteRecord(athleteIdentity)
    : null;
  const latestAnalysis = athleteIdentity.athleteId || athleteIdentity.athleteUid || athleteIdentity.athleteName
    ? getLatestCoachMatchAnalysisForAthlete(athleteIdentity)
    : null;
  const latestAssignmentMedia = liveAssignments.find((item) => item.mediaAssetPath) || null;
  const competitionMedia = latestAnalysis?.mediaAssetPath
    ? {
        title: latestAnalysis.mediaTitle || (currentLang === "es" ? "Video de analisis" : "Analysis video"),
        assetPath: latestAnalysis.mediaAssetPath,
        thumbnailPath: latestAnalysis.mediaThumbnailPath || "",
        mediaType: latestAnalysis.mediaType || "Video"
      }
    : (latestAssignmentMedia?.mediaAssetPath
        ? {
            title: latestAssignmentMedia.mediaTitle || latestAssignmentMedia.title,
            assetPath: latestAssignmentMedia.mediaAssetPath,
            thumbnailPath: latestAssignmentMedia.mediaThumbnailPath || "",
            mediaType: latestAssignmentMedia.mediaType || "Video"
          }
        : null);
  const cornerPlan = getAthleteCornerPlan(getRawAthleteRecord(profile.name) || profile);
  return [
    {
      title: currentLang === "es" ? "Datos del atleta" : "Athlete Basics",
      lines: [
        `${currentLang === "es" ? "Nombre" : "Name"}: ${profile.name || unknown}`,
        `${currentLang === "es" ? "Estilo" : "Style"}: ${style}`,
        `${currentLang === "es" ? "Peso" : "Weight"}: ${weight} (${weightClass})`,
        `${currentLang === "es" ? "Experiencia" : "Experience"}: ${years} ${yearsLabel} - ${level}`,
        `${currentLang === "es" ? "Posicion preferida" : "Preferred position"}: ${position}`,
        `${currentLang === "es" ? "Estrategia" : "Strategy"}: ${strategy}`
      ]
    },
    {
      title: currentLang === "es" ? "Entrenamiento" : "Training",
      lines: [
        `${currentLang === "es" ? "Rutinas" : "Routines"}: ${profile.trainingRoutines || na}`,
        `${currentLang === "es" ? "Volumen" : "Volume"}: ${profile.trainingVolume || na}`,
        `${currentLang === "es" ? "Tecnica foco" : "Technique focus"}: ${profile.trainingFocus || na}`
      ]
    },
    {
      title: currentLang === "es" ? "Plan de competencia" : "Competition Plan",
      lines: [
        `${currentLang === "es" ? "Estrategia A/B/C" : "Strategy A/B/C"}: ${strategyPlans.join(" | ") || na}`,
        `${currentLang === "es" ? "Seguros" : "Safe moves"}: ${profile.safeMoves || na}`,
        `${currentLang === "es" ? "Arriesgados" : "Risky moves"}: ${profile.riskyMoves || na}`,
        `${currentLang === "es" ? "Resultados" : "Results"}: ${profile.resultsHistory || na}`
      ]
    },
    {
      title: currentLang === "es" ? "Resumen de torneo" : "Tournament Snapshot",
      lines: [
        `${currentLang === "es" ? "Plan activo" : "Active plan"}: ${latestPlan?.title || na}`,
        `${currentLang === "es" ? "Siguiente tarea" : "Next assignment"}: ${liveAssignments[0]?.title || na}`,
        `${currentLang === "es" ? "Film mas reciente" : "Latest film"}: ${competitionMedia?.title || na}`,
        `${currentLang === "es" ? "Competition cue" : "Competition cue"}: ${cornerPlan?.competitionCue || profile.coachSignal || na}`,
        `${currentLang === "es" ? "Advertencia principal" : "Primary warning"}: ${cornerPlan?.safetyWarnings?.[0] || profile.injuryNotes || none}`,
        `${currentLang === "es" ? "Journal" : "Journal"}: ${latestJournal?.entryDate ? `${formatPlanDateLabel(latestJournal.entryDate)} - ${latestJournal.energy || na}` : na}`
      ],
      actions: competitionMedia?.assetPath ? [{
        label: currentLang === "es" ? "Abrir film" : "Open film",
        url: competitionMedia.assetPath
      }] : []
    },
    {
      title: currentLang === "es" ? "Tecnicas predeterminadas" : "Default Techniques",
      lines: [
        `${currentLang === "es" ? "Neutral" : "Neutral"}: ${neutralList.join(", ") || na}`,
        `${currentLang === "es" ? "Arriba" : "Top"}: ${topList.join(", ") || na}`,
        `${currentLang === "es" ? "Abajo" : "Bottom"}: ${bottomList.join(", ") || na}`,
        `${currentLang === "es" ? "Defensa" : "Defense"}: ${defenseList.join(", ") || na}`,
        `${currentLang === "es" ? "Otro" : "Other"}: ${[
          profile.techniques?.neutralOther,
          profile.techniques?.topOther,
          profile.techniques?.bottomOther,
          profile.techniques?.defenseOther
        ].filter(Boolean).join(" - ") || na}`
      ]
    },
    {
      title: currentLang === "es" ? "Coaching rapido" : "Coaching Quick",
      lines: [
        `${currentLang === "es" ? "Posicion favorita" : "Favorite position"}: ${favoritePosition}`,
        `${currentLang === "es" ? "Tendencia" : "Tendency"}: ${tendency}`,
        `${currentLang === "es" ? "Error bajo presion" : "Common error"}: ${profile.pressureError || na}`,
        `${currentLang === "es" ? "Senal clave" : "Coach signal"}: ${profile.coachSignal || na}`,
        `${currentLang === "es" ? "Top ofensivo" : "Top offense"}: ${offense}`,
        `${currentLang === "es" ? "Top defensivo" : "Top defense"}: ${defense}`,
        `Tags: ${tags}`,
        `${currentLang === "es" ? "Focus actual" : "Current focus"}: ${(latestNotes?.nextFocus || []).slice(0, 2).join(" | ") || na}`,
        `${currentLang === "es" ? "Ultimo match analysis" : "Latest match analysis"}: ${latestAnalysis?.summary || na}`
      ]
    },
    {
      title: currentLang === "es" ? "Experiencia internacional" : "International Experience",
      lines: [
        `${currentLang === "es" ? "Competencia internacional" : "International competition"}: ${intl}`,
        `${currentLang === "es" ? "Paises/eventos" : "Countries/events"}: ${profile.internationalEvents || na}`,
        `${currentLang === "es" ? "Anos" : "Years"}: ${profile.internationalYears || na}`,
        `${currentLang === "es" ? "Indicaciones" : "Coach cues"}: ${coachCues}`,
        `${currentLang === "es" ? "Que ayuda" : "What helps"}: ${profile.cueNotes || na}`,
        `${currentLang === "es" ? "Lesiones/limites" : "Injuries/limits"}: ${profile.injuryNotes || none}`
      ]
    }
  ];
}

function renderCompetitionPreview(profile) {
  renderCompetitionManager(profile);
  if (!competitionPreview) return;
  competitionPreview.innerHTML = "";
  const sections = buildCompetitionPreview(profile);
  if (!sections.length) {
    const isCoachContext = isCoachRouteContext();
    const card = document.createElement("div");
    card.className = "mini-card";
    card.innerHTML = `
      <h3>${currentLang === "es" ? "Competition / Corner View" : "Competition / Corner View"}</h3>
      <p class="small muted">${currentLang === "es"
        ? (isCoachContext
            ? "Selecciona un atleta en Athletes para ver su vista de competencia."
            : "Completa el perfil del atleta para cargar la vista de competencia.")
        : (isCoachContext
            ? "Select an athlete in Athletes to load the competition view."
            : "Complete the athlete profile to load the competition view.")}</p>
    `;
    competitionPreview.appendChild(card);
    return;
  }
  sections.forEach((section) => {
    const card = document.createElement("div");
    card.className = "mini-card";
    card.innerHTML = `<h3>${section.title}</h3>`;
    const list = document.createElement("ul");
    list.className = "list";
    section.lines.forEach((line) => {
      const li = document.createElement("li");
      li.textContent = line;
      list.appendChild(li);
    });
    card.appendChild(list);
    if (Array.isArray(section.actions) && section.actions.length) {
      const actions = document.createElement("div");
      actions.className = "assignment-card-actions";
      section.actions.forEach((action) => {
        if (!action?.url) return;
        const button = document.createElement("button");
        button.type = "button";
        button.className = "ghost";
        button.textContent = action.label;
        button.addEventListener("click", () => window.open(action.url, "_blank", "noopener,noreferrer"));
        actions.appendChild(button);
      });
      if (actions.children.length) {
        card.appendChild(actions);
      }
    }
    competitionPreview.appendChild(card);
  });
}

